SELECT interactions.interaction_id, interactions.interaction_type, customers.first_name, customers.last_name
FROM interactions
INNER JOIN customers ON interactions.customer_id = customers.customer_id;

SELECT COUNT(interaction_id) AS total_interactions
FROM interactions
WHERE customer_id = 1;

SELECT customers.first_name, customers.last_name, customers.email, categories.category_name
FROM customers
JOIN categories ON customers.category = categories.category_id;
